/* 
 * 质数爆炸模拟（预处理素数表版）
 * 关键技术：埃拉托斯特尼筛法预处理
 */
#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const int MOD = 1e9 + 7;
const int MAX = 1e6 + 1e5; // 足够大的范围

vector<int> primes;
vector<bool> is_prime(MAX, true);

void sieve() {
    is_prime[0] = is_prime[1] = false;
    for (int i = 2; i < MAX; ++i) {
        if (is_prime[i]) {
            primes.push_back(i);
            for (int j = 2*i; j < MAX; j += i) {
                is_prime[j] = false;
            }
        }
    }
}

int next_prime(int x) {
    return *upper_bound(primes.begin(), primes.end(), x);
}

int main() {
    sieve();
    int N, K;
    cin >> N >> K;

    ll pos = N;
    while (K--) {
        int p = next_prime(pos);
        pos = (p + (p - pos)) % MOD;
    }

    cout << pos << endl;
    return 0;
}
```

